mapper.update:
UPDATE MIS_ROLE
SET role_name = #{roleName}, remark = #{remark}
WHERE id = #{id}

mapper.select:
SELECT permission_code FROM MIS_PERMISSION
WHERE id IN (
    SELECT permission_id FROM MIS_ROLE_PERMISSION WHERE role_id = #{roleId}
)

mapper.insert:
INSERT INTO MIS_ROLE_PERMISSION (id, role_id, permission_id)
VALUES (#{id}, #{roleId}, (
    SELECT id FROM MIS_PERMISSION WHERE permission_code = #{permission}
))
